BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?step ?stepName WHERE {
  VALUES ?root { <http://api.koneksys.com/cameo/TMT/block/TMT::Project::Components::TMT%2520Project> }
  VALUES ?target { <http://api.koneksys.com/cameo/TMT/package/TMT::Project::Work%2520Packages::Telescope::WorkPackages::Control::Alignment%2520and%2520Phasing%2520System::Systems%2520Engineering::10%2520Analysis::Roll-up%2520Analyses::Error%2520Budgets::Pupil%2520Alignment%2520Error%2520Budget> }
  ?root (vocab:Element_ownedElement+ / ^vocab:Element_owner) ?any .
  ?root (vocab:Element_ownedElement+) ?target .
  OPTIONAL { ?any vocab:NamedElement_name ?stepName . }
  BIND(?any AS ?step)
} LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?ancestor ?ancestorName WHERE {
  VALUES ?root { <http://api.koneksys.com/cameo/TMT/block/TMT::Project::Components::TMT%2520Project> }
  VALUES ?target { <http://api.koneksys.com/cameo/TMT/package/TMT::Project::Work%2520Packages::Telescope::WorkPackages::Control::Alignment%2520and%2520Phasing%2520System::Systems%2520Engineering::10%2520Analysis::Roll-up%2520Analyses::Error%2520Budgets::Pupil%2520Alignment%2520Error%2520Budget> }
  ?target ( ^vocab:Element_owner+ ) ?ancestor .
  ?ancestor vocab:NamedElement_name ?ancestorName .
  FILTER(?ancestor = ?root)
} LIMIT 25
